import logging
import json
import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.eventgrid.models import EventGridEvent
from azure.identity import DefaultAzureCredential

def main(blob: func.InputStream):
    # Initialize credentials
    credential = DefaultAzureCredential()
    
    # Blob Storage setup
    blob_service_client = BlobServiceClient(
        account_url="https://yourstorageaccount.blob.core.windows.net",
        credential=credential
    )
    
    # Cosmos DB setup
    cosmos_client = CosmosClient(
        account_url="https://yourcosmosdbaccount.documents.azure.com:443/",
        credential=credential
    )
    
    # Event Grid setup
    event_grid_client = EventGridPublisherClient(
        endpoint="https://youreventgridtopic.westus2-1.eventgrid.azure.net/api/events",
        credential=credential
    )
    
    try:
        # Read blob content
        blob_content = blob.read().decode('utf-8')
        logging.info(f"Processing blob: {blob.name}")
        
        # Process data (example: count words)
        word_count = len(blob_content.split())
        result = {
            "blob_name": blob.name,
            "word_count": word_count,
            "processed_at": "2023-01-01T00:00:00Z"
        }
        
        # Write to Cosmos DB
        database = cosmos_client.get_database_client("YourDatabase")
        container = database.get_container_client("YourContainer")
        container.upsert_item(result)
        
        # Send notification via Event Grid
        event = EventGridEvent(
            event_type="BlobProcessed",
            subject=f"blob/{blob.name}",
            data=result,
            data_version="1.0"
        )
        
        event_grid_client.send([event])
        
        logging.info("Processing completed successfully")
        
    except Exception as e:
        logging.error(f"Error processing blob: {str(e)}")
        raise